CREATE TABLE challenge_instances (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL REFERENCES challenges(id), owner_user_id uuid NOT NULL REFERENCES users(id), owner_team_id uuid REFERENCES teams(id), competition_id uuid REFERENCES competitions(id), runtime_provider text NOT NULL, runtime_id text NOT NULL DEFAULT '', runtime_network_id text NOT NULL DEFAULT '', status text NOT NULL CHECK(status IN ('starting','running','restarting','resetting','stopping','stopped','failed','expired')), access_url text NOT NULL DEFAULT '', host_port int, internal_port int, generation int NOT NULL DEFAULT 1, flag_hmac bytea NOT NULL, flag_ciphertext bytea NOT NULL, error_code text NOT NULL DEFAULT '', started_at timestamptz, expires_at timestamptz, stopped_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), version bigint NOT NULL DEFAULT 1);
CREATE UNIQUE INDEX challenge_instances_active_uq ON challenge_instances(challenge_id,owner_user_id,coalesce(competition_id,'00000000-0000-0000-0000-000000000000'::uuid)) WHERE status IN ('starting','running','restarting','resetting','stopping');
CREATE INDEX challenge_instances_expiry_idx ON challenge_instances(status,expires_at);
CREATE TABLE instance_operations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), instance_id uuid NOT NULL REFERENCES challenge_instances(id), actor_id uuid NOT NULL REFERENCES users(id), operation text NOT NULL CHECK(operation IN ('start','restart','stop','reset','extend','expire','reconcile')), from_status text NOT NULL, to_status text NOT NULL, result text NOT NULL DEFAULT 'pending', idempotency_key text NOT NULL, error_code text NOT NULL DEFAULT '', requested_at timestamptz NOT NULL DEFAULT now(), finished_at timestamptz, request_id text NOT NULL DEFAULT '');
CREATE UNIQUE INDEX instance_operations_idempotency_uq ON instance_operations(actor_id,idempotency_key);
CREATE TABLE instance_runtime_jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), instance_id uuid NOT NULL REFERENCES challenge_instances(id) ON DELETE CASCADE, operation_id uuid NOT NULL UNIQUE REFERENCES instance_operations(id), operation text NOT NULL, status text NOT NULL DEFAULT 'queued', payload jsonb NOT NULL DEFAULT '{}', attempts int NOT NULL DEFAULT 0, available_at timestamptz NOT NULL DEFAULT now(), locked_at timestamptz, finished_at timestamptz, last_error text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE instance_ports (port int PRIMARY KEY CHECK(port BETWEEN 1024 AND 65535), instance_id uuid NOT NULL UNIQUE REFERENCES challenge_instances(id) ON DELETE CASCADE, allocated_at timestamptz NOT NULL DEFAULT now(), released_at timestamptz);
CREATE UNIQUE INDEX instance_ports_active_uq ON instance_ports(port) WHERE released_at IS NULL;
CREATE TABLE instance_runtime_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), instance_id uuid NOT NULL REFERENCES challenge_instances(id) ON DELETE CASCADE, type text NOT NULL, provider_status text NOT NULL DEFAULT '', payload jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE instance_quota_usages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES users(id), team_id uuid REFERENCES teams(id), day date NOT NULL, starts int NOT NULL DEFAULT 0, runtime_seconds bigint NOT NULL DEFAULT 0, UNIQUE(user_id,team_id,day));
CREATE TABLE instance_cleanup_jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), instance_id uuid NOT NULL UNIQUE REFERENCES challenge_instances(id), status text NOT NULL DEFAULT 'pending', scheduled_at timestamptz NOT NULL, attempts int NOT NULL DEFAULT 0, last_error text NOT NULL DEFAULT '');

CREATE TABLE submissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), challenge_id uuid NOT NULL REFERENCES challenges(id), team_id uuid REFERENCES teams(id), competition_id uuid REFERENCES competitions(id), instance_id uuid REFERENCES challenge_instances(id), result text NOT NULL CHECK(result IN ('correct','incorrect','duplicate','rate_limited','error')), awarded_score int NOT NULL DEFAULT 0, candidate_fingerprint text NOT NULL, ip inet, user_agent text NOT NULL DEFAULT '', request_id text NOT NULL DEFAULT '', duration_ms int NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX submissions_lookup_idx ON submissions(user_id,challenge_id,competition_id,created_at DESC);
CREATE INDEX submissions_anticheat_idx ON submissions(candidate_fingerprint,created_at DESC);
CREATE TABLE solve_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), challenge_id uuid NOT NULL REFERENCES challenges(id), team_id uuid REFERENCES teams(id), competition_id uuid REFERENCES competitions(id), submission_id uuid NOT NULL UNIQUE REFERENCES submissions(id), score int NOT NULL, solved_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX solve_records_unique_uq ON solve_records(user_id,challenge_id,coalesce(competition_id,'00000000-0000-0000-0000-000000000000'::uuid));
CREATE TABLE blood_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL REFERENCES challenges(id), competition_id uuid REFERENCES competitions(id), user_id uuid NOT NULL REFERENCES users(id), submission_id uuid NOT NULL UNIQUE REFERENCES submissions(id), rank int NOT NULL CHECK(rank BETWEEN 1 AND 3), award int NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX blood_records_rank_uq ON blood_records(challenge_id,coalesce(competition_id,'00000000-0000-0000-0000-000000000000'::uuid),rank);
CREATE TABLE score_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), team_id uuid REFERENCES teams(id), competition_id uuid REFERENCES competitions(id), challenge_id uuid REFERENCES challenges(id), type text NOT NULL, delta int NOT NULL, reference_type text NOT NULL, reference_id uuid NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX score_events_idempotent_uq ON score_events(type,reference_type,reference_id,user_id);
CREATE INDEX score_events_rank_idx ON score_events(competition_id,user_id,created_at);
CREATE TABLE submission_rate_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), challenge_id uuid NOT NULL REFERENCES challenges(id), bucket timestamptz NOT NULL, attempts int NOT NULL, UNIQUE(user_id,challenge_id,bucket));
CREATE TABLE checker_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), submission_id uuid NOT NULL REFERENCES submissions(id), runtime_id text NOT NULL DEFAULT '', result text NOT NULL, duration_ms int NOT NULL, error_code text NOT NULL DEFAULT '', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE scoreboard_snapshots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), competition_id uuid NOT NULL REFERENCES competitions(id), kind text NOT NULL, payload jsonb NOT NULL, frozen boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
ALTER TABLE competition_settlements ADD CONSTRAINT competition_settlements_snapshot_fk FOREIGN KEY(snapshot_id) REFERENCES scoreboard_snapshots(id);

